2	-- Company    : SLAC National Accelerator Laboratory
3	-------------------------------------------------------------------------------
4	-- Description:
5	-- This is an implementation of an 1-to-8-byte input CRC32 calculation.
6	-- The polynomial is fixed to 0x04C11DB7, the "standard CRC32 polynomial."
7	-- The initialization value is configurable, but defaults to 0xFFFFFFFF.
8	--
9	-- This implementation is direct, so no bytes need to be appended to the data.
10	--
11	-- Bytes are reversed on input before being used for the CRC calculation,
12	-- and the CRC register is reversed on output just before a final XOR with
13	-- 0xFFFFFFFF.
14	--
15	-- This version utilizes parallel CRC calculations, and as a result generally
16	-- should meet much tighter timing constraints and run at higher frequencies.
17	-- (relative to Crc32.vhd and CRC32Rtl.vhd).
18	--
19	-- With a data input size of 4 bytes, this module is compatible with the
20	-- previous CRC32Rtl.vhdl module in the StdLib.
21	-------------------------------------------------------------------------------
22	-- This file is part of 'SLAC Firmware Standard Library'.
23	-- It is subject to the license terms in the LICENSE.txt file found in the
24	-- top-level directory of this distribution and at:
25	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
26	-- No part of 'SLAC Firmware Standard Library', including this file,
27	-- may be copied, modified, propagated, or distributed except according to
28	-- the terms contained in the LICENSE.txt file.
29	-------------------------------------------------------------------------------
30	
31	library ieee;
32	use ieee.std_logic_1164.all;
33	use ieee.std_logic_arith.all;
34	use ieee.std_logic_unsigned.all;
35	
36	library surf;
37	use surf.StdRtlPkg.all;
38	use surf.CrcPkg.all;
39	
40	entity Crc32Parallel is
41	   generic (
42	      TPD_G            : time             := 1 ns;
43	      RST_POLARITY_G   : sl               := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
44	      RST_ASYNC_G      : boolean          := false;
45	      BYTE_WIDTH_G     : positive         := 4;
46	      INPUT_REGISTER_G : boolean          := true;
47	      CRC_INIT_G       : slv(31 downto 0) := x"FFFFFFFF");
48	   port (
49	      crcPwrOnRst  : in  sl               := not RST_POLARITY_G;
50	      crcOut       : out slv(31 downto 0);         -- CRC output
51	      crcRem       : out slv(31 downto 0);         -- CRC interim remainder
52	      crcClk       : in  sl;            -- system clock
53	      crcDataValid : in  sl;  -- indicate that new data arrived and CRC can be computed
54	      crcDataWidth : in  slv(2 downto 0);  -- indicate width in bytes minus 1, 0 - 1 byte, 1 - 2 bytes ... , 7 - 8 bytes
55	      crcIn        : in  slv((BYTE_WIDTH_G*8-1) downto 0);  -- input data for CRC calculation
56	      crcInit      : in  slv(31 downto 0) := CRC_INIT_G;  -- optional override of CRC_INIT_G
57	      crcReset     : in  sl);           -- initializes CRC logic to crcInit
58	end Crc32Parallel;
59	
60	architecture rtl of Crc32Parallel is
61	
62	   type RegType is record
63	      crc       : slv(31 downto 0);
64	      data      : slv((BYTE_WIDTH_G*8-1) downto 0);
65	      valid     : sl;
66	      reset     : sl;
67	      byteWidth : slv(2 downto 0);
68	   end record RegType;
69	
70	   constant REG_INIT_C : RegType := (
71	      crc       => CRC_INIT_G,
72	      data      => (others => '0'),
73	      valid     => '0',
74	      reset     => '0',
75	      byteWidth => (others => '0'));
76	
77	   signal r   : RegType := REG_INIT_C;
78	   signal rin : RegType;
79	
80	begin
81	
82	   assert (BYTE_WIDTH_G > 0 and BYTE_WIDTH_G <= 8) report "BYTE_WIDTH_G must be in the range [1,8]" severity failure;
83	
84	   comb : process(crcDataValid, crcDataWidth, crcIn, crcInit, crcReset, r)
85	      variable v         : RegType;
86	      variable prevCrc   : slv(31 downto 0);
87	      variable byteWidth : slv(2 downto 0);
88	      variable valid     : sl;
89	      variable reset     : sl;
90	      variable data      : slv((BYTE_WIDTH_G*8-1) downto 0);
91	   begin
92	      -- Latch the current value
93	      v := r;
94	
95	      -- Latch the signals
96	      v.byteWidth := crcDataWidth;
97	      v.valid     := crcDataValid;
98	      v.reset     := crcReset;
99	
100	      -- Transpose the input data
101	      for byte in (BYTE_WIDTH_G-1) downto 0 loop
102	         if (crcDataWidth >= BYTE_WIDTH_G-byte-1) then
103	            for b in 0 to 7 loop
104	               v.data((byte+1)*8-1-b) := crcIn(byte*8+b);
105	            end loop;
106	         else
107	            v.data((byte+1)*8-1 downto byte*8) := (others => '0');
108	         end if;
109	      end loop;
110	
111	      -- Select where to register the inputs
112	      if (INPUT_REGISTER_G) then
113	         byteWidth := r.byteWidth;
114	         valid     := r.valid;
115	         reset     := r.reset;
116	         data      := r.data;
117	      else
118	         byteWidth := v.byteWidth;
119	         valid     := v.valid;
120	         reset     := v.reset;
121	         data      := v.data;
122	      end if;
123	
124	      -- Reset handling
125	      if (reset = '0') then
126	         -- Use remainder from previous cycle
127	         prevCrc := r.crc;
128	      else
129	         -- Pre-load the remainder
130	         prevCrc := crcInit;
131	      end if;
132	
133	      -- Calculate CRC in parallel - implementation used depends on the
134	      -- byte width in use.
135	      if (valid = '1') then
136	         case (byteWidth) is
137	            when "000" =>
138	               v.crc := crc32Parallel1Byte(prevCrc, data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-1)*8));
139	            when "001" =>
140	               if (BYTE_WIDTH_G >= 2) then
141	                  v.crc := crc32Parallel2Byte(prevCrc, data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-2)*8));
142	               end if;
143	            when "010" =>
144	               if (BYTE_WIDTH_G >= 3) then
145	                  v.crc := crc32Parallel3Byte(prevCrc, data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-3)*8));
146	               end if;
147	            when "011" =>
148	               if (BYTE_WIDTH_G >= 4) then
149	                  v.crc := crc32Parallel4Byte(prevCrc, data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-4)*8));
150	               end if;
151	            when "100" =>
152	               if (BYTE_WIDTH_G >= 5) then
153	                  v.crc := crc32Parallel5Byte(prevCrc, data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-5)*8));
154	               end if;
155	            when "101" =>
156	               if (BYTE_WIDTH_G >= 6) then
157	                  v.crc := crc32Parallel6Byte(prevCrc, data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-6)*8));
158	               end if;
159	            when "110" =>
160	               if (BYTE_WIDTH_G >= 7) then
161	                  v.crc := crc32Parallel7Byte(prevCrc, data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-7)*8));
162	               end if;
163	            when "111" =>
164	               if (BYTE_WIDTH_G = 8) then
165	                  v.crc := crc32Parallel8Byte(prevCrc, data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-8)*8));
166	               end if;
167	            when others => v.crc := (others => '0');
168	         end case;
169	      else
170	         -- No change
171	         v.crc := prevCrc;
172	      end if;
173	
174	      -- Register the variable for next clock cycle
175	      rin <= v;
176	
177	      -- Outputs
178	      crcRem <= r.crc;
179	
180	      -- Transpose each byte in the data out and invert
181	      -- This inversion is equivalent to an XOR of the CRC register with xFFFFFFFF
182	      for byte in 0 to 3 loop
183	         for b in 0 to 7 loop
184	            crcOut(byte*8+b) <= not(r.crc((byte+1)*8-1-b));
185	         end loop;
186	      end loop;
187	
188	   end process;
189	
190	   seq : process (crcClk, crcPwrOnRst) is
191	   begin
192	      if (RST_ASYNC_G and crcPwrOnRst = RST_POLARITY_G) then
193	         r <= REG_INIT_C after TPD_G;
194	      elsif (rising_edge(crcClk)) then
195	         if (RST_ASYNC_G = false and crcPwrOnRst = RST_POLARITY_G) then
196	            r <= REG_INIT_C after TPD_G;
197	         else
198	            r <= rin after TPD_G;
199	         end if;
200	      end if;
201	   end process seq;
202	
203	end rtl;
