         crcDataWidth => crcDataWidth,
         crcIn        => crcIn,
         crcReset     => crcReset,
         crcInit      => crcInit,
         crcOut       => crcOut,
         crcRem       => crcRem,
         crcPwrOnRst  => crcPwrOnRst);

end architecture mapping;

