94	         for b in 0 to 7 loop
95	            if (crcDataWidth >= BYTE_WIDTH_G-byte-1) then
96	               v.data((byte+1)*8-1-b) := crcIn(byte*8+b);
97	            else
98	               v.data((byte+1)*8-1-b) := '0';
99	            end if;
100	         end loop;
101	      end loop;
102	
103	      -- Select where to register the inputs
