15	
16	library ieee;
17	use ieee.std_logic_1164.all;
18	use ieee.std_logic_arith.all;
19	use ieee.std_logic_unsigned.all;
20	
21	library surf;
22	use surf.StdRtlPkg.all;
23	use surf.EthCrc32Pkg.all;
24	
25	entity EthCrc32Parallel is
26	   generic (
27	      TPD_G          : time                   := 1 ns;
28	      RST_POLARITY_G : sl                     := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
29	      USE_DSP_G      : boolean                := false;  -- true is not tested yet
30	      CRC_INIT_G     : slv(31 downto 0)       := x"FFFFFFFF";
31	      BYTE_WIDTH_G   : positive range 1 to 16 := 16);  -- Maximum byte width (1-16 supported)
32	   port (
33	      crcClk       : in  sl;
34	      crcReset     : in  sl;
35	      crcDataValid : in  sl;
36	      crcDataWidth : in  slv(3 downto 0);  -- # of bytes minus 1 (example: 0 - 1 byte, 1 - 2 bytes ... , 15 - 16 bytes)
37	      crcIn        : in  slv((BYTE_WIDTH_G*8-1) downto 0);
38	      crcOut       : out slv(31 downto 0));
39	end EthCrc32Parallel;
40	
41	architecture rtl of EthCrc32Parallel is
42	
43	   type RegType is record
44	      valid     : sl;
45	      byteWidth : slv(3 downto 0);
46	      data      : slv((BYTE_WIDTH_G*8-1) downto 0);
47	      crc       : slv(31 downto 0);
48	   end record RegType;
49	
50	   constant REG_INIT_C : RegType := (
51	      valid     => '0',
52	      byteWidth => (others => '0'),
53	      data      => (others => '0'),
54	      crc       => CRC_INIT_G);
55	
56	   signal r   : RegType := REG_INIT_C;
57	   signal rin : RegType;
58	
59	   signal dspInA : Slv96Array(31 downto 0);
60	   signal dspInB : Slv192Array(31 downto 0);
61	   signal dspOut : slv(31 downto 0);
62	
63	   -- attribute dont_touch           : string;
64	   -- attribute dont_touch of r      : signal is "true";
65	   -- attribute dont_touch of dspInA : signal is "true";
66	   -- attribute dont_touch of dspInB : signal is "true";
67	   -- attribute dont_touch of dspOut : signal is "true";
68	
69	begin
70	
71	   GEN_DSP : if (USE_DSP_G) generate
72	      GEN_VEC :
73	      for i in 31 downto 0 generate
74	
75	         GEN_A : if (BYTE_WIDTH_G < 9) generate
76	
77	            U_Xor : entity surf.DspXor
78	               generic map (
79	                  TPD_G          => TPD_G,
80	                  RST_POLARITY_G => RST_POLARITY_G,
81	                  INIT_G         => CRC_INIT_G(i),
82	                  WIDTH_G        => 96)
83	               port map (
84	                  clk  => crcClk,
85	                  rst  => crcReset,     -- ASYNC RST
86	                  ain  => dspInA(i),
87	                  pOut => dspOut(i));
88	
89	         end generate;
90	
91	         GEN_B : if (BYTE_WIDTH_G >= 9) generate
92	
93	            U_Xor : entity surf.DspXor
94	               generic map (
95	                  TPD_G          => TPD_G,
96	                  RST_POLARITY_G => RST_POLARITY_G,
97	                  INIT_G         => CRC_INIT_G(i),
98	                  WIDTH_G        => 192)
99	               port map (
100	                  clk  => crcClk,
101	                  rst  => crcReset,     -- ASYNC RST
102	                  ain  => dspInB(i),
103	                  pOut => dspOut(i));
104	
105	         end generate;
106	
107	      end generate GEN_VEC;
108	   end generate;
109	
110	   comb : process(crcDataValid, crcDataWidth, crcIn, crcReset, dspOut, r)
111	      variable v          : RegType;
112	      variable dspOut     : slv(31 downto 0);
113	      variable xorBitMapA : Slv96Array(31 downto 0);
114	      variable xorBitMapB : Slv192Array(31 downto 0);
115	      variable prevCrc    : slv(31 downto 0);
116	   begin
117	      -- Latch the current value
118	      v := r;
119	
120	      -- Reset the variables
121	      xorBitMapA := (others => (others => '0'));
122	      xorBitMapB := (others => (others => '0'));
123	
124	      v.byteWidth := crcDataWidth;
125	      v.valid     := crcDataValid;
126	
127	      -- Transpose the input data
128	      for byte in (BYTE_WIDTH_G-1) downto 0 loop
129	         if (crcDataWidth >= BYTE_WIDTH_G-byte-1) then
130	            for b in 0 to 7 loop
131	               v.data((byte+1)*8-1-b) := crcIn(byte*8+b);
132	            end loop;
133	         else
134	            v.data((byte+1)*8-1 downto byte*8) := (others => '0');
135	         end if;
136	      end loop;
137	
138	      if (USE_DSP_G = false) then
139	         if (crcReset = not RST_POLARITY_G) then
140	            prevCrc := r.crc;
141	         else
142	            prevCrc := CRC_INIT_G;
143	         end if;
144	      end if;
145	
146	      -- Calculate CRC in parallel - implementation used depends on the byte width in use.
147	      if (r.valid = '1') then
148	         case (r.byteWidth) is
149	            ---------------------------------------------------------------------------------------------------------------
150	            when x"0" =>                -- 1 Byte (8-bits)
151	               if (USE_DSP_G) then
152	                  if (BYTE_WIDTH_G < 9) then
153	                     xorBitMap1Byte(xorBitMapA, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-1)*8));
154	                  else
155	                     xorBitMap1Byte(xorBitMapB, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-1)*8));
156	                  end if;
157	               else
158	                  v.crc := crc32Parallel1Byte(prevCrc, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-1)*8));
159	               end if;
160	            ---------------------------------------------------------------------------------------------------------------
161	            when x"1" =>                -- 2 Byte (16-bits)
162	               if (BYTE_WIDTH_G >= 2) then
163	                  if (USE_DSP_G) then
164	                     if (BYTE_WIDTH_G < 9) then
165	                        xorBitMap2Byte(xorBitMapA, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-2)*8));
166	                     else
167	                        xorBitMap2Byte(xorBitMapB, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-2)*8));
168	                     end if;
169	                  else
170	                     v.crc := crc32Parallel2Byte(prevCrc, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-2)*8));
171	                  end if;
172	               end if;
173	            ---------------------------------------------------------------------------------------------------------------
174	            when x"2" =>                -- 3 Byte (24-bits)
175	               if (BYTE_WIDTH_G >= 3) then
176	                  if (USE_DSP_G) then
177	                     if (BYTE_WIDTH_G < 9) then
178	                        xorBitMap3Byte(xorBitMapA, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-3)*8));
179	                     else
180	                        xorBitMap3Byte(xorBitMapB, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-3)*8));
181	                     end if;
182	                  else
183	                     v.crc := crc32Parallel3Byte(prevCrc, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-3)*8));
184	                  end if;
185	               end if;
186	            ---------------------------------------------------------------------------------------------------------------
187	            when x"3" =>                -- 4 Byte (32-bits)
188	               if (BYTE_WIDTH_G >= 4) then
189	                  if (USE_DSP_G) then
190	                     if (BYTE_WIDTH_G < 9) then
191	                        xorBitMap4Byte(xorBitMapA, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-4)*8));
192	                     else
193	                        xorBitMap4Byte(xorBitMapB, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-4)*8));
194	                     end if;
195	                  else
196	                     v.crc := crc32Parallel4Byte(prevCrc, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-4)*8));
197	                  end if;
198	               end if;
199	            ---------------------------------------------------------------------------------------------------------------
200	            when x"4" =>                -- 5 Byte (40-bits)
201	               if (BYTE_WIDTH_G >= 5) then
202	                  if (USE_DSP_G) then
203	                     if (BYTE_WIDTH_G < 9) then
204	                        xorBitMap5Byte(xorBitMapA, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-5)*8));
205	                     else
206	                        xorBitMap5Byte(xorBitMapB, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-5)*8));
207	                     end if;
208	                  else
209	                     v.crc := crc32Parallel5Byte(prevCrc, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-5)*8));
210	                  end if;
211	               end if;
212	            ---------------------------------------------------------------------------------------------------------------
213	            when x"5" =>                -- 6 Byte (48-bits)
214	               if (BYTE_WIDTH_G >= 6) then
215	                  if (USE_DSP_G) then
216	                     if (BYTE_WIDTH_G < 9) then
217	                        xorBitMap6Byte(xorBitMapA, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-6)*8));
218	                     else
219	                        xorBitMap6Byte(xorBitMapB, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-6)*8));
220	                     end if;
221	                  else
222	                     v.crc := crc32Parallel6Byte(prevCrc, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-6)*8));
223	                  end if;
224	               end if;
225	            ---------------------------------------------------------------------------------------------------------------
226	            when x"6" =>                -- 7 Byte (56-bits)
227	               if (BYTE_WIDTH_G >= 7) then
228	                  if (USE_DSP_G) then
229	                     if (BYTE_WIDTH_G < 9) then
230	                        xorBitMap7Byte(xorBitMapA, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-7)*8));
231	                     else
232	                        xorBitMap7Byte(xorBitMapB, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-7)*8));
233	                     end if;
234	                  else
235	                     v.crc := crc32Parallel7Byte(prevCrc, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-7)*8));
236	                  end if;
237	               end if;
238	            ---------------------------------------------------------------------------------------------------------------
239	            when x"7" =>                -- 8 Byte (64-bits)
240	               if (BYTE_WIDTH_G >= 8) then
241	                  if (USE_DSP_G) then
242	                     if (BYTE_WIDTH_G < 9) then
243	                        xorBitMap8Byte(xorBitMapA, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-8)*8));
244	                     else
245	                        xorBitMap8Byte(xorBitMapB, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-8)*8));
246	                     end if;
247	                  else
248	                     v.crc := crc32Parallel8Byte(prevCrc, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-8)*8));
249	
250	                  end if;
251	               end if;
252	            ---------------------------------------------------------------------------------------------------------------
253	            when x"8" =>                -- 9 Byte (72-bits)
254	               if (BYTE_WIDTH_G >= 9) then
255	                  if (USE_DSP_G) then
256	                     xorBitMap9Byte(xorBitMapB, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-9)*8));
257	                  else
258	                     v.crc := crc32Parallel9Byte(prevCrc, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-9)*8));
259	                  end if;
260	               end if;
261	            ---------------------------------------------------------------------------------------------------------------
262	            when x"9" =>                -- 10 Byte (80-bits)
263	               if (BYTE_WIDTH_G >= 10) then
264	                  if (USE_DSP_G) then
265	                     xorBitMap10Byte(xorBitMapB, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-10)*8));
266	                  else
267	                     v.crc := crc32Parallel10Byte(prevCrc, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-10)*8));
268	                  end if;
269	               end if;
270	            ---------------------------------------------------------------------------------------------------------------
271	            when x"A" =>                -- 11 Byte (88-bits)
272	               if (BYTE_WIDTH_G >= 11) then
273	                  if (USE_DSP_G) then
274	                     xorBitMap11Byte(xorBitMapB, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-11)*8));
275	                  else
276	                     v.crc := crc32Parallel11Byte(prevCrc, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-11)*8));
277	                  end if;
278	               end if;
279	            ---------------------------------------------------------------------------------------------------------------
280	            when x"B" =>                -- 12 Byte (96-bits)
281	               if (BYTE_WIDTH_G >= 12) then
282	                  if (USE_DSP_G) then
283	                     xorBitMap12Byte(xorBitMapB, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-12)*8));
284	                  else
285	                     v.crc := crc32Parallel12Byte(prevCrc, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-12)*8));
286	                  end if;
287	               end if;
288	            ---------------------------------------------------------------------------------------------------------------
289	            when x"C" =>                -- 13 Byte (104-bits)
290	               if (BYTE_WIDTH_G >= 13) then
291	                  if (USE_DSP_G) then
292	                     xorBitMap13Byte(xorBitMapB, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-13)*8));
293	                  else
294	                     v.crc := crc32Parallel13Byte(prevCrc, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-13)*8));
295	                  end if;
296	               end if;
297	            ---------------------------------------------------------------------------------------------------------------
298	            when x"D" =>                -- 14 Byte (112-bits)
299	               if (BYTE_WIDTH_G >= 14) then
300	                  if (USE_DSP_G) then
301	                     xorBitMap14Byte(xorBitMapB, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-14)*8));
302	                  else
303	                     v.crc := crc32Parallel14Byte(prevCrc, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-14)*8));
304	                  end if;
305	               end if;
306	            ---------------------------------------------------------------------------------------------------------------
307	            when x"E" =>                -- 15 Byte (120-bits)
308	               if (BYTE_WIDTH_G >= 15) then
309	                  if (USE_DSP_G) then
310	                     xorBitMap15Byte(xorBitMapB, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-15)*8));
311	                  else
312	                     v.crc := crc32Parallel15Byte(prevCrc, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-15)*8));
313	                  end if;
314	               end if;
315	            ---------------------------------------------------------------------------------------------------------------
316	            when x"F" =>                -- 16 Byte (128-bits)
317	               if (BYTE_WIDTH_G = 16) then
318	                  if (USE_DSP_G) then
319	                     xorBitMap16Byte(xorBitMapB, dspOut, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-16)*8));
320	                  else
321	                     v.crc := crc32Parallel16Byte(prevCrc, r.data(BYTE_WIDTH_G*8-1 downto (BYTE_WIDTH_G-16)*8));
322	                  end if;
323	               end if;
324	            ---------------------------------------------------------------------------------------------------------------
325	            when others =>
326	               null;
327	         ---------------------------------------------------------------------------------------------------------------
328	         end case;
329	      elsif (USE_DSP_G = false) then
330	         v.crc := prevCrc;
331	      end if;
332	
333	      -- Register the variable for next clock cycle
334	      rin <= v;
335	
336	      -- Transpose each byte in the data out and invert
337	      -- This inversion is equivalent to an XOR of the CRC register with xFFFFFFFF
338	      for byte in 0 to 3 loop
339	         for b in 0 to 7 loop
340	            if (USE_DSP_G) then
341	               crcOut(byte*8+b) <= not(dspOut((byte+1)*8-1-b));
342	            else
343	               crcOut(byte*8+b) <= not(r.crc((byte+1)*8-1-b));
344	            end if;
345	         end loop;
346	      end loop;
347	
348	      -- Outputs
349	      dspInA <= xorBitMapA;
350	      dspInB <= xorBitMapB;
351	
352	   end process;
353	
354	   seq : process (crcClk) is
355	   begin
356	      if (rising_edge(crcClk)) then
357	         r <= rin after TPD_G;
358	      end if;
359	   end process seq;
360	
361	end rtl;
362

